const webhookItem = $('Webhook Evolution').first();
if (!webhookItem) {
  throw new Error('Normalizar Mensagem: payload do webhook ausente');
}

const source = webhookItem.json.body ?? webhookItem.json;
const data = source.data ?? {};
const message = data.message ?? {};
const imageMessage = message.imageMessage ?? {};
const audioMessage = message.audioMessage ?? {};

const rawText = String(
  message.conversation ||
  message.extendedTextMessage?.text ||
  imageMessage.caption ||
  ''
).trim();

const hasImage = imageMessage && Object.keys(imageMessage).length > 0;
const hasAudio = audioMessage && Object.keys(audioMessage).length > 0;
const messageType = hasImage ? 'image' : hasAudio ? 'audio' : 'text';

const rawBase64 = String(
  data.base64 ||
  source.base64 ||
  message.base64 ||
  imageMessage.base64 ||
  audioMessage.base64 ||
  ''
).trim();
const mediaBase64 = rawBase64.replace(/^data:[^;]+;base64,/, '');
const mimeType = String(imageMessage.mimetype || audioMessage.mimetype || data.mimetype || '').trim();
const messageId = String(data.key?.id || '').trim();
const minBase64Length = messageType === 'image' ? 500 : 100;
const canAnalyzeMedia = Boolean((messageType === 'image' || messageType === 'audio') && mediaBase64 && mimeType && mediaBase64.length >= minBase64Length);

const extensionFromMime = (type) => {
  const normalized = String(type || '').toLowerCase();
  if (!normalized) return 'bin';
  if (normalized.includes('jpeg')) return 'jpg';
  if (normalized.includes('png')) return 'png';
  if (normalized.includes('webp')) return 'webp';
  if (normalized.includes('ogg')) return 'ogg';
  if (normalized.includes('mpeg')) return 'mp3';
  if (normalized.includes('mp4')) return 'mp4';
  const raw = normalized.split('/')[1] || 'bin';
  return raw.split(';')[0].split(',')[0].trim() || 'bin';
};

let fallbackText = rawText;
if (!fallbackText) {
  if (messageType === 'image') {
    fallbackText = 'O cliente enviou uma imagem.';
  } else if (messageType === 'audio') {
    fallbackText = 'O cliente enviou um audio.';
  }
}

const item = {
  json: {
    messageType,
    rawText,
    fallbackText,
    mimeType,
    messageId,
    canAnalyzeMedia,
  },
};

if (canAnalyzeMedia) {
  const extension = extensionFromMime(mimeType);
  item.binary = {
    data: {
      data: mediaBase64,
      mimeType,
      fileExtension: extension,
      fileName: `${messageType}-${messageId || Date.now()}.${extension}`,
    },
  };
}

return [item];

const row = $json && typeof $json === 'object' ? $json : {};
const enabled = row.assistant_enabled !== false;
const rawMode = String(row.mode || 'auto').trim().toLowerCase();
const normalizedMode = ['auto', 'manual', 'hybrid'].includes(rawMode) ? rawMode : 'auto';
const humanHandoffEnabled = row.human_handoff_enabled !== false;
const defaultHandoffMessage = String(row.default_handoff_message || 'Atendimento em modo manual. A Aura nao respondera automaticamente.').trim();
const shouldAutoReply = enabled && normalizedMode === 'auto';

return [{
  json: {
    assistantEnabled: enabled,
    assistantMode: normalizedMode,
    humanHandoffEnabled,
    defaultHandoffMessage,
    shouldAutoReply,
  },
}];

const lead = $('Normalizar Lead').first().json;
const settings = $('Resolver Modo Aura').first().json;

return [{
  json: {
    status: 'manual_mode',
    assistantMode: settings.assistantMode,
    assistantEnabled: settings.assistantEnabled,
    remoteJid: lead.remoteJid,
    waNumber: lead.waNumber,
    note: settings.defaultHandoffMessage,
  },
}];

const msg = $('Mensagem Interpretada').first().json;
const settings = $('Resolver Modo Aura').first().json;
const text = String(msg.messageText || '').trim();

const normalize = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase();

const normalizedText = normalize(text);
const handoffRules = [
  { reason: 'manutencao', patterns: ['chuveiro queimou', 'chuveiro queimado', 'sem agua', 'sem energia', 'ar condicionado nao funciona', 'ar condicionado quebrou', 'tv nao funciona', 'manutencao', 'quarto com problema', 'problema no quarto', 'banheiro entupido', 'vazamento'] },
  { reason: 'reclamacao', patterns: ['quero reclamar', 'fazer reclamacao', 'fazer uma reclamacao', 'reclamacao', 'reclamar', 'insatisfeito', 'insatisfacao'] },
  { reason: 'humano', patterns: ['quero falar com humano', 'quero falar com atendente', 'quero falar com uma pessoa', 'falar com humano', 'falar com atendente', 'atendente humano', 'me chama um humano'] },
  { reason: 'cobranca', patterns: ['cobranca errada', 'cobranca indevida', 'cobraram errado', 'pagamento errado', 'estorno', 'reembolso'] },
  { reason: 'urgente', patterns: ['urgente', 'emergencia', 'socorro'] },
  { reason: 'cancelamento sensivel', patterns: ['quero cancelar', 'cancelamento', 'cancelar reserva'] },
];

let matchedRule = null;
let matchedPattern = null;
for (const rule of handoffRules) {
  const found = rule.patterns.find((pattern) => normalizedText.includes(pattern));
  if (found) {
    matchedRule = rule.reason;
    matchedPattern = found;
    break;
  }
}

const needsHuman = Boolean(settings.humanHandoffEnabled !== false && matchedRule);
const handoffSummary = needsHuman
  ? `Handoff humano: ${matchedRule}. Mensagem do cliente: ${text || 'sem conteudo legivel'}`
  : '';

return [{
  json: {
    ...msg,
    needsHuman,
    handoffReason: matchedRule,
    handoffMatchedPattern: matchedPattern,
    handoffSummary,
  },
}];

const lead = $('Normalizar Lead').first().json;
const classification = $('Classificar Handoff Humano').first().json;

return [{
  json: {
    lead_id: lead.waNumber,
    new_stage: 'Aguardando Humano',
    summary: classification.handoffSummary || 'Handoff humano solicitado.',
    prioridade: 'alta',
    ultima_interacao: new Date().toISOString(),
    handoff_reason: classification.handoffReason || 'motivo_nao_identificado',
  },
}];

const validRules = items
  .map((item) => item.json || {})
  .filter((rule) => Object.keys(rule).length > 0)
  .filter((rule) => rule.active !== false)
  .filter((rule) => String(rule.category || '').trim() && String(rule.rule_key || '').trim());

const grouped = new Map();
for (const rule of validRules) {
  const category = String(rule.category).trim();
  const ruleKey = String(rule.rule_key).trim();
  const value = String(rule.value || '').trim() || 'Nao cadastrado';
  if (!grouped.has(category)) grouped.set(category, []);
  grouped.get(category).push(`- ${ruleKey}: ${value}`);
}

const knowledgeContext = grouped.size
  ? Array.from(grouped.entries())
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([category, entries]) => [`[${category}]`, ...entries.sort()].join('\n'))
      .join('\n\n')
  : 'Nenhuma regra operacional cadastrada.';

return [{
  json: {
    knowledgeContext,
    ruleCount: validRules.length,
  },
}];

const msg = $("Mensagem Interpretada").first().json;
const extracted = $("Gemini - Extrair Dados Busca").first().json.output || {};
const text = String(msg.messageText || "").trim();

const adults = Number(extracted.adults || 2);
const children_6_11 = Number(extracted.children_6_11 || 0);
const children_0_5 = Number(extracted.children_0_5 || 0);
const totalGuests = adults + children_6_11 + children_0_5;

const normalize = (value) => String(value || "")
  .normalize("NFD")
  .replace(/[\u0300-\u036f]/g, "")
  .toLowerCase();

const normalizedText = normalize(text);

// 1. Coleta tarifas base
const rates = $("Supabase - Get Room Rates").all()
  .map((item) => item.json || {})
  .filter((rate) => Object.keys(rate).length > 0)
  .filter((rate) => rate.active !== false);

// 2. Coleta inventario
const inventoryList = $("Supabase - Get Room Inventory").all()
  .map((item) => item.json || {});

// 3. Coleta mapeamentos dinamicos (Dashboard)
const roomMappings = $("Supabase - Get Room Mappings").all()
  .map((item) => item.json || {});

const parseDateValue = (value) => {
  if (!value) return null;
  if (value instanceof Date) return Number.isNaN(value.getTime()) ? null : value;
  const textValue = String(value).trim();
  if (!textValue) return null;
  const iso = textValue.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (iso) {
    const date = new Date(Date.UTC(Number(iso[1]), Number(iso[2]) - 1, Number(iso[3])));
    return Number.isNaN(date.getTime()) ? null : date;
  }
  return null;
};

const parseMessageDates = (value) => {
  const found = [];
  const seen = new Set();
  const now = new Date();
  const defaultYear = now.getUTCFullYear();
  const defaultMonth = now.getUTCMonth() + 1;

  const getLocalToday = () => {
    const now = new Date();
    const brShift = -3;
    const brDate = new Date(now.getTime() + brShift * 3600000);
    return new Date(Date.UTC(brDate.getUTCFullYear(), brDate.getUTCMonth(), brDate.getUTCDate()));
  };

  const pushDate = (year, month, day) => {
    const date = new Date(Date.UTC(year, month - 1, day));
    if (Number.isNaN(date.getTime())) return;
    const key = date.toISOString().slice(0, 10);
    if (seen.has(key)) return;
    seen.add(key);
    found.push(date);
  };

  const rangeMatches = [...String(value).matchAll(/\b(\d{1,2})(?:\/(\d{1,2})(?:\/(\d{2,4}))?)?\s*(?:a|-|até|ate)\s*(\d{1,2})(?:\/(\d{1,2})(?:\/(\d{2,4}))?)?\b/gi)];
  for (const match of rangeMatches) {
    const startDay = Number(match[1]);
    const startMonth = match[2] ? Number(match[2]) : (match[5] ? Number(match[5]) : defaultMonth);
    let startYear = match[3] ? Number(match[3]) : (match[6] ? Number(match[6]) : defaultYear);
    const endDay = Number(match[4]);
    const endMonth = match[5] ? Number(match[5]) : startMonth;
    let endYear = match[6] ? Number(match[6]) : startYear;
    if (startYear < 100) startYear += 2000;
    if (endYear < 100) endYear += 2000;
    pushDate(startYear, startMonth, startDay);
    pushDate(endYear, endMonth, endDay);
  }

  const normalized = normalize(value);
  if (/\b(hoje|hj)\b/.test(normalized)) {
    const d = getLocalToday();
    pushDate(d.getUTCFullYear(), d.getUTCMonth() + 1, d.getUTCDate());
  }

  return found.sort((a, b) => a.getTime() - b.getTime());
};

const formatCurrency = (value) => `R$ ${Number(value || 0).toFixed(2).replace(".", ",")}`;
const formatDate = (date) => `${String(date.getUTCDate()).padStart(2, "0")}/${String(date.getUTCMonth() + 1).padStart(2, "0")}/${date.getUTCFullYear()}`;

const parsedDates = parseMessageDates(text);
const checkIn = parsedDates[0] || null;
const checkOut = parsedDates[1] || (parsedDates[0] ? new Date(parsedDates[0].getTime() + 86400000) : null);

if (!checkIn || !checkOut || checkOut <= checkIn) {
  return [{ json: { rateContext: "BASE DE TARIFAS: informe datas e hóspedes.", nights: 0 } }];
}

const nights = Math.round((checkOut.getTime() - checkIn.getTime()) / 86400000);
const roomTypes = ["Apto Terreo", "Apto Superior", "Chale", "Apto Anexo"];
const lines = [];

for (const roomType of roomTypes) {
  const mapping = roomMappings.find(m => m.room_type === roomType) || {};
  const maxCap = Number(mapping.max_capacity || 3);

  if (totalGuests > maxCap) {
    lines.push(`- ${roomType}: CAPACIDADE EXCEDIDA (Máx ${maxCap}). Sugerimos reservar +1 quarto.`);
    continue;
  }

  let total = 0;
  let allNightsCovered = true;

  let cursor = new Date(checkIn);
  while (cursor < checkOut) {
    const dateStr = cursor.toISOString().slice(0, 10);
    const inv = inventoryList.find(i => i.room_type === roomType && i.date === dateStr);

    let base = 0;
    let extraAdult = Number(mapping.default_extra_adult_price || 100);
    let child611 = Number(mapping.default_child_6_11_price || 80);

    if (inv) {
      base = Number(inv.base_price || 0);
      extraAdult = Number(inv.extra_adult_price || extraAdult);
      child611 = Number(inv.child_6_11_price || child611);
    } else {
      const applicable = rates
        .filter(r => r.room_type === roomType)
        .map(r => ({ ...r, from: parseDateValue(r.date_from), to: parseDateValue(r.date_to) }))
        .filter(r => r.from && r.to && cursor >= r.from && cursor <= r.to);

      if (!applicable.length) { allNightsCovered = false; break; }
      base = Number(applicable[0].base_price || 0);
    }

    let guestsToCharge = [];
    for (let i = 0; i < adults; i++) guestsToCharge.push(extraAdult);
    for (let i = 0; i < children_6_11; i++) guestsToCharge.push(child611);
    for (let i = 0; i < children_0_5; i++) guestsToCharge.push(0);

    guestsToCharge.sort((a, b) => b - a);
    const charged = guestsToCharge.slice(2); 
    total += base + charged.reduce((s, v) => s + v, 0);

    cursor = new Date(cursor.getTime() + 86400000);
  }

  if (!allNightsCovered) {
    lines.push(`- ${roomType}: INDISPONIVEL.`);
    continue;
  }

  lines.push(`- ${roomType}: ${formatCurrency(total)} (Total para ${totalGuests} pessoas).`);
}

const rateContext = `DISPONIBILIDADE E TARIFAS (${formatDate(checkIn)} a ${formatDate(checkOut)}):\n${lines.join("\n")}`;

return [{ json: { rateContext, guests: { adults, children_6_11, children_0_5 }, nights } }];

const input = typeof $input.item.json === 'object' && $input.item.json !== null ? $input.item.json : {};
const new_stage = input.new_stage || 'Novo Lead';
const summary = input.summary || 'Lead sem resumo informado';

return [{
  json: {
    new_stage,
    summary,
    lead_id: $('Normalizar Lead').first().json.remoteJid,
    ultima_interacao: new Date().toISOString()
  }
}];

